class AuthServicer(auth_pb2_grpc.AuthServiceServicer):
    def Login(self, request, context):
        print(f"AuthService: Received Login request for user: {request.username}")
        if request.username == "user" and request.password == "pass":
            return auth_pb2.LoginResponse(success=True, message="Login successful", token="fake-auth-token-123")
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid username or password")
            return auth_pb2.LoginResponse(success=False, message="Invalid credentials", token="")

    def Register(self, request, context):
        print(f"AuthService: Received Register request for user: {request.username}, email: {request.email}")
        # In a real scenario, you'd add the user to a database
        if "fail" in request.username:
            context.set_code(grpc.StatusCode.ALREADY_EXISTS)
            context.set_details("Username already taken")
            return auth_pb2.RegisterResponse(success=False, message="Username already taken", user_id="")
        
        user_id = f"user-{hash(request.username) % 10000}"
        return auth_pb2.RegisterResponse(success=True, message="Registration successful", user_id=user_id)

